VALUES
  ('police-b20a8cf8-moex-00544', 'police-b20a8cf8', 'police-b20a8cf8-moex-110-585f428e', 'sub-police-b20a8cf8-03', NULL, 'single_choice', '勘察小組進行刑案現場勘察時，下列有關之敘述何者正確？①由內而外②由近而遠③由高而低', '["由左而右", "", "", ""]'::jsonb, 3, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:25+00:00", "source_pdf_sha1": "f0cafe2c1496", "answer_pdf_sha1": "ab39a5c2813f", "source_family": "moex-gov-tw", "moex": {"exam_code": "110070", "c": "503", "s": "1701", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "刑案現場處理與刑事鑑識", "year": "110", "exam_name": "110年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試、退除役軍人轉任公務人員考試", "original_question_number": 2, "answer_corrected": false, "flags": ["incomplete_options"], "civil_slug": "police", "civil_category": "刑事警察人員"}'::jsonb, NULL),
  ('police-b20a8cf8-moex-00545', 'police-b20a8cf8', 'police-b20a8cf8-moex-110-585f428e', 'sub-police-b20a8cf8-03', NULL, 'single_choice', '下列指紋顯現方法原理何者錯誤？', '["寧海德林試劑原理是與指紋殘留物中的胺基酸產生反應", "碘燻法原理是碘分子溶入指紋殘留物中之油脂", "硝酸銀法原理是和指紋殘留物中蛋白質產生反應", "粉末法原理是利用指紋殘留物之水分和油脂吸附粉末，而使指紋顯現"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:25+00:00", "source_pdf_sha1": "f0cafe2c1496", "answer_pdf_sha1": "ab39a5c2813f", "source_family": "moex-gov-tw", "moex": {"exam_code": "110070", "c": "503", "s": "1701", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "刑案現場處理與刑事鑑識", "year": "110", "exam_name": "110年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試、退除役軍人轉任公務人員考試", "original_question_number": 3, "answer_corrected": false, "flags": [], "civil_slug": "police", "civil_category": "刑事警察人員"}'::jsonb, NULL),
  ('police-b20a8cf8-moex-00546', 'police-b20a8cf8', 'police-b20a8cf8-moex-110-585f428e', 'sub-police-b20a8cf8-03', NULL, 'single_choice', '實施勘察採證注意原則，下列何者錯誤？', '["重要跡證在採取或製模前宜先照相", "勘察人員發現重要跡證時，應迅速報告勘察組長", "命案現場屍體之勘察，應於法醫到場後，配合法醫解剖之重點，應放置比例尺", "當確定所有物證均已蒐集完畢，現場勘查紀錄報告已填寫，並在現場待重建的所有事項獲得肯 定答案後，應由勘察組長複勘，現場始得解除封鎖"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:25+00:00", "source_pdf_sha1": "f0cafe2c1496", "answer_pdf_sha1": "ab39a5c2813f", "source_family": "moex-gov-tw", "moex": {"exam_code": "110070", "c": "503", "s": "1701", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "刑案現場處理與刑事鑑識", "year": "110", "exam_name": "110年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試、退除役軍人轉任公務人員考試", "original_question_number": 4, "answer_corrected": false, "flags": [], "civil_slug": "police", "civil_category": "刑事警察人員"}'::jsonb, NULL),
  ('police-b20a8cf8-moex-00547', 'police-b20a8cf8', 'police-b20a8cf8-moex-110-585f428e', 'sub-police-b20a8cf8-03', NULL, 'single_choice', '槍枝、子彈、彈頭（殼）證物之處理原則，下列何者錯誤？', '["槍枝應視個案情況及必要性，採取指紋、生物跡證或射擊殘跡等", "槍枝如有同時採取2種以上跡證之需要時，採證之順序為指紋、生物跡證、射擊殘跡", "現場彈頭（殼）應視個案情況留意其上可能之微物跡證，如有必要宜先採集鑑驗", "採取子彈、彈頭（殼）應避免以金屬器具直接夾取而破壞其上之痕跡"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:25+00:00", "source_pdf_sha1": "f0cafe2c1496", "answer_pdf_sha1": "ab39a5c2813f", "source_family": "moex-gov-tw", "moex": {"exam_code": "110070", "c": "503", "s": "1701", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "刑案現場處理與刑事鑑識", "year": "110", "exam_name": "110年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試、退除役軍人轉任公務人員考試", "original_question_number": 5, "answer_corrected": false, "flags": [], "civil_slug": "police", "civil_category": "刑事警察人員"}'::jsonb, NULL),
  ('police-b20a8cf8-moex-00548', 'police-b20a8cf8', 'police-b20a8cf8-moex-110-585f428e', 'sub-police-b20a8cf8-03', NULL, 'single_choice', '下列何者不是犯罪現場重建的步驟？', '["落實犯罪現場勘查、廣泛蒐集相關資料", "形成合理的假設模型，並驗證是否屬實", "善用鑑識結果，大膽假設", "局部與完整的案情重建"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:25+00:00", "source_pdf_sha1": "f0cafe2c1496", "answer_pdf_sha1": "ab39a5c2813f", "source_family": "moex-gov-tw", "moex": {"exam_code": "110070", "c": "503", "s": "1701", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "刑案現場處理與刑事鑑識", "year": "110", "exam_name": "110年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試、退除役軍人轉任公務人員考試", "original_question_number": 6, "answer_corrected": true, "flags": ["answer_corrected_skip_v1"], "civil_slug": "police", "civil_category": "刑事警察人員"}'::jsonb, NULL),
  ('police-b20a8cf8-moex-00549', 'police-b20a8cf8', 'police-b20a8cf8-moex-110-585f428e', 'sub-police-b20a8cf8-03', NULL, 'single_choice', '有關現場勘察人員之敘述，下列何者錯誤？', '["抵達現場後，應注意現場封鎖範圍是否妥當，必要時應報告現場指揮官再予調整", "現場勘察人員對於住宅或車輛實施勘察採證，除非自願性同意，或有急迫情形報請現場指揮官 同意者外，應有搜索票或鑑定許可書", "請求管轄檢察官核發鑑定許可書時，應以書面為之。但案件已有檢察官指揮者，得以言詞為之", "命案現場屍體之勘察，除初步了解身分及必要之紀錄外，應於檢察官到場後進行"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:25+00:00", "source_pdf_sha1": "f0cafe2c1496", "answer_pdf_sha1": "ab39a5c2813f", "source_family": "moex-gov-tw", "moex": {"exam_code": "110070", "c": "503", "s": "1701", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "刑案現場處理與刑事鑑識", "year": "110", "exam_name": "110年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試、退除役軍人轉任公務人員考試", "original_question_number": 7, "answer_corrected": false, "flags": [], "civil_slug": "police", "civil_category": "刑事警察人員"}'::jsonb, NULL),
  ('police-b20a8cf8-moex-00550', 'police-b20a8cf8', 'police-b20a8cf8-moex-110-585f428e', 'sub-police-b20a8cf8-03', NULL, 'single_choice', '關於精液檢體試驗法，下列敘述何者正確？', '["聖誕樹法（Christmastreestain）是一種精液的呈色試驗，試劑與酸性磷酸酶（acidphosphatase） 反應生成粉紅色", "酸性磷酸酶呈色試驗是一種精液特異反應，並不會與其他體液進行反應", "要判定是否有精液，一定要發現精蟲（spermatozoa）", "人類精液前列腺抗原法（Prostaticspecificantigen）是一種精液分析法，其檢測精液中前列腺抗 原（p30）是否存在"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:25+00:00", "source_pdf_sha1": "f0cafe2c1496", "answer_pdf_sha1": "ab39a5c2813f", "source_family": "moex-gov-tw", "moex": {"exam_code": "110070", "c": "503", "s": "1701", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "刑案現場處理與刑事鑑識", "year": "110", "exam_name": "110年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試、退除役軍人轉任公務人員考試", "original_question_number": 8, "answer_corrected": false, "flags": [], "civil_slug": "police", "civil_category": "刑事警察人員"}'::jsonb, NULL),
  ('police-b20a8cf8-moex-00551', 'police-b20a8cf8', 'police-b20a8cf8-moex-110-585f428e', 'sub-police-b20a8cf8-03', NULL, 'single_choice', '拉曼光譜儀（RamanSpectrometer）應用於微物跡證、火藥爆裂物與毒品等未知物的分析，下列敘 述何者正確？', '["拉曼光譜激發光源能量越強能提供更容易分析的光譜訊號", "斯托克斯位移（Stokesshift）的激發光源波長大於放射光源波長", "含水成分較多的樣品因為C─H與C=O鍵結等極化率（polarizability）較差，拉曼光譜訊號比較 弱，因此較適合採用拉曼光譜儀（RamanSpectrometer）進行分析", "一化合物的拉曼光譜和紅外吸收光譜完全相同，但拉曼光譜儀使用上較方便"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:25+00:00", "source_pdf_sha1": "f0cafe2c1496", "answer_pdf_sha1": "ab39a5c2813f", "source_family": "moex-gov-tw", "moex": {"exam_code": "110070", "c": "503", "s": "1701", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "刑案現場處理與刑事鑑識", "year": "110", "exam_name": "110年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試、退除役軍人轉任公務人員考試", "original_question_number": 9, "answer_corrected": false, "flags": [], "civil_slug": "police", "civil_category": "刑事警察人員"}'::jsonb, NULL),
  ('police-b20a8cf8-moex-00552', 'police-b20a8cf8', 'police-b20a8cf8-moex-110-585f428e', 'sub-police-b20a8cf8-03', NULL, 'single_choice', '古柯鹼Scott呈色試驗法，下列敘述何者正確？', '["試劑含有二甲氨基苯甲醛（p-dimethylaminobenzaldehyde）", "當試劑呈現粉紅色時表示有古柯鹼存在", "當試劑呈現紫色時表示有古柯鹼存在", "試劑含有硫氰酸鈷（Cobalt（II）thiocyanate）"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:25+00:00", "source_pdf_sha1": "f0cafe2c1496", "answer_pdf_sha1": "ab39a5c2813f", "source_family": "moex-gov-tw", "moex": {"exam_code": "110070", "c": "503", "s": "1701", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "刑案現場處理與刑事鑑識", "year": "110", "exam_name": "110年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試、退除役軍人轉任公務人員考試", "original_question_number": 10, "answer_corrected": false, "flags": [], "civil_slug": "police", "civil_category": "刑事警察人員"}'::jsonb, NULL),
  ('police-b20a8cf8-moex-00553', 'police-b20a8cf8', 'police-b20a8cf8-moex-110-585f428e', 'sub-police-b20a8cf8-03', NULL, 'single_choice', '一氧化碳中毒（CarbonMonoxidePoisoning）的發生是由於碳氫化合物不完全燃燒所產生的一 氧化碳，因為其無色、無味且不易被察覺，且與血紅素（hemoglobin）的親和力大約為氧氣的 200-250倍，當一氧化碳和血紅素結合後，使血紅素無法與氧氣結合，導致細胞缺氧而死亡。關於 一氧化碳的分析，下列敘述何者正確？', '["微量擴散法（microdiffusion test）採用氣相層析法（gas chromatography）不須加入催化劑可直 接分析血液中血紅素的濃度", "微量擴散法採用分光光度法（spectrophotometricmethod）不須加入催化劑可直接分析血液中一 氧化碳的濃度", "目前一氧化碳的分析方法已改用放射免疫分析（radioimmunoassay）", "火災現場罹難者因吸入大量不完全燃燒的碳氫化合物而導致血液中一氧化碳濃度含量極高，可 用來判斷是抵達火災現場之前或之後死亡"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:25+00:00", "source_pdf_sha1": "f0cafe2c1496", "answer_pdf_sha1": "ab39a5c2813f", "source_family": "moex-gov-tw", "moex": {"exam_code": "110070", "c": "503", "s": "1701", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "刑案現場處理與刑事鑑識", "year": "110", "exam_name": "110年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試、退除役軍人轉任公務人員考試", "original_question_number": 11, "answer_corrected": false, "flags": [], "civil_slug": "police", "civil_category": "刑事警察人員"}'::jsonb, NULL)
